class Solution { int[] dp; public int minCostClimbingStairs(int[] cost) { int n = cost.length; dp = new int[n+1]; Arrays.fill(dp, -1); return Math.min(solve(0, n, cost), dp[1]); } public int solve(int i, int n, int[] cost){ if(i>=n) return 0; if(dp[i] != -1) return dp[i]; int take = solve(i+1, n, cost); int take1 = solve(i+2, n, cost); return dp[i] = cost[i] + Math.min(take, take1); } }